import{_ as o,o as t,c as n,a2 as a}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Dev tools","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dev-tools.md","filePath":"guide/dev-tools.md","lastUpdated":1782055054000}'),r={name:"guide/dev-tools.md"};function s(l,e,d,i,c,p){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="dev-tools" tabindex="-1">Dev tools <a class="header-anchor" href="#dev-tools" aria-label="Permalink to &quot;Dev tools&quot;">​</a></h1><p>Developer-only conveniences that are gated out of production builds. They exist to help inspect and debug the game; none of them change shipped behaviour.</p><h2 id="unlock-all-zones-flo-469-flo-475" tabindex="-1">Unlock all zones (FLO-469, FLO-475) <a class="header-anchor" href="#unlock-all-zones-flo-469-flo-475" aria-label="Permalink to &quot;Unlock all zones (FLO-469, FLO-475)&quot;">​</a></h2><p>By default the world map gates fast-travel behind sequential conquest: a world opens only once the previous one is conquered (ADR 0005, see <a href="./world-map">World map &amp; zones</a>). To <strong>inspect every map</strong> without playing through the campaign, an override marks all registered zones (<code>forest</code>, <code>human-lands</code>, <code>empire</code>, <code>mountains</code>) as unlocked, so each is selectable and travelable from the world-map overlay (press <strong>M</strong> in play).</p><p>It is <strong>travel/routing only</strong> — it does not grant conquest credit, write to the save, or alter any other progression. Regular players on the live site see the normal conquest gate unless they explicitly opt in (see below).</p><h3 id="dev-preview-builds-flo-469" tabindex="-1">Dev / preview builds (FLO-469) <a class="header-anchor" href="#dev-preview-builds-flo-469" aria-label="Permalink to &quot;Dev / preview builds (FLO-469)&quot;">​</a></h3><p>The gate is resolved by <code>isDevZoneUnlockEnabled()</code> in <a href="../../src/game/world/devUnlock.ts"><code>src/game/world/devUnlock.ts</code></a>, read once at startup in <code>App</code> via <code>isAllZonesTravelUnlocked()</code>. Resolution (first match wins):</p><table tabindex="0"><thead><tr><th>Condition</th><th>Unlock all zones?</th></tr></thead><tbody><tr><td><code>VITE_DEV_UNLOCK_ZONES=true</code></td><td><strong>on</strong> — even in a built/preview bundle</td></tr><tr><td><code>VITE_DEV_UNLOCK_ZONES=false</code></td><td><strong>off</strong> — even in a dev build (exercise the real gate)</td></tr><tr><td>flag unset, <code>npm run dev</code></td><td><strong>on</strong> (dev build default)</td></tr><tr><td>flag unset, prod build</td><td><strong>off</strong> (unless prod opt-in below)</td></tr></tbody></table><p>So the common dev cases need no setup:</p><ul><li><strong>Local inspection:</strong> <code>npm run dev</code> → open the app, press <strong>M</strong>, travel anywhere.</li><li><strong>Test the real conquest gate in dev:</strong> <code>VITE_DEV_UNLOCK_ZONES=false npm run dev</code>.</li><li><strong>Deployed preview the board can poke:</strong> build with <code>VITE_DEV_UNLOCK_ZONES=true npm run build</code> (do <strong>not</strong> set this on the production deploy).</li></ul><blockquote><p>⚠️ Do not set <code>VITE_DEV_UNLOCK_ZONES=true</code> for the production Cloudflare Pages build — that would ship the override and let <strong>every</strong> player skip progression. Use the prod opt-in below instead.</p></blockquote><h3 id="prod-opt-in-for-the-board-flo-475" tabindex="-1">Prod opt-in for the board (FLO-475) <a class="header-anchor" href="#prod-opt-in-for-the-board-flo-475" aria-label="Permalink to &quot;Prod opt-in for the board (FLO-475)&quot;">​</a></h3><p>On the <strong>live</strong> site (<code>korovany.aimost.pl</code>), the board can unlock every zone without changing the deploy or affecting other players:</p><ol><li>Open <code>https://korovany.aimost.pl/?unlockzones=1</code> (once).</li><li>The choice is persisted to <code>localStorage</code> (<code>korovany-unlockzones</code>), so later visits work without the query param.</li><li>Press <strong>M</strong> in play and fast-travel anywhere.</li></ol><p>To turn it off again, clear site data / remove the <code>korovany-unlockzones</code> key from localStorage in devtools.</p><p>This path is resolved by <code>resolveProdZoneUnlockOptIn()</code> and combined with the dev gate in <code>isAllZonesTravelUnlocked()</code>. It is still travel/routing only — no conquest credit and no save writes.</p><blockquote><p>⚠️ Opening all zones to <strong>everyone</strong> without a per-browser opt-in is a one-line deploy flip (<code>VITE_DEV_UNLOCK_ZONES=true</code> on the prod build). That is intentionally <strong>not</strong> the default; use <code>?unlockzones=1</code> unless the board explicitly wants global unlock.</p></blockquote><h3 id="scene-caveat" tabindex="-1">Scene caveat <a class="header-anchor" href="#scene-caveat" aria-label="Permalink to &quot;Scene caveat&quot;">​</a></h3><p>Every zone has its own scene (<code>createZoneScene</code> in <a href="../../src/scenes/zoneScenes.ts"><code>src/scenes/zoneScenes.ts</code></a>): <code>forest</code>, <code>human-lands</code>, <code>empire</code> (palace) and <code>mountains</code> (Black Crown Pass). Travelling with the override mounts each zone&#39;s real scene — there is no forest fallback for the unlocked maps.</p>',19)])])}const v=o(r,[["render",s]]);export{u as __pageData,v as default};
